import json
with open('baseline-packages.json') as f:
    baseline = json.loads('[' + f.read().replace('}\n{', '},{') + ']')
with open('after-cpm-packages.json') as f:
    after = json.loads('[' + f.read().replace('}\n{', '},{') + ']')

def extract(data):
    result = {}
    for doc in data:
        for proj in doc.get('projects', []):
            name = proj['path'].split('/')[-1]
            pkgs = {}
            for fw in proj.get('frameworks', []):
                for pkg in fw.get('topLevelPackages', []):
                    pkgs[pkg['id']] = {'requested': pkg.get('requestedVersion',''), 'resolved': pkg.get('resolvedVersion','')}
            result[name] = pkgs
    return result

b = extract(baseline)
a = extract(after)

print('=== BASELINE ===')
for proj in sorted(b):
    for pkg in sorted(b[proj]):
        print(f'{proj}: {pkg} requested={b[proj][pkg][\"requested\"]} resolved={b[proj][pkg][\"resolved\"]}')

print()
print('=== AFTER CPM ===')
for proj in sorted(a):
    for pkg in sorted(a[proj]):
        print(f'{proj}: {pkg} requested={a[proj][pkg][\"requested\"]} resolved={a[proj][pkg][\"resolved\"]}')

print()
